function pixelIconSVG(name, size = 16, color = '#0A0A0A') {
  const cells = PIXEL_GRIDS[name] || [];
  const rects = cells.map(([x, y]) => `<rect x="${x}" y="${y}" width="1" height="1" fill="${color}"/>`).join('');
  return `<svg class="pixel-icon" width="${size}" height="${size}" viewBox="0 0 7 7" shape-rendering="crispEdges">${rects}</svg>`;
}

function pixforgeLogoSVG(size = 28) {
  return `<svg width="${size}" height="${size}" viewBox="0 0 16 16" shape-rendering="crispEdges">
    <rect x="6" y="1" width="4" height="3" fill="#0A0A0A" />
    <rect x="4" y="4" width="4" height="3" fill="#FF6B1A" />
    <rect x="2" y="7" width="4" height="3" fill="#E8331C" />
    <rect x="4" y="10" width="4" height="3" fill="#FF6B1A" />
    <rect x="6" y="13" width="4" height="2" fill="#0A0A0A" />
  </svg>`;
}

// Inject all elements with data-pixel-icon="name" / data-pixel-size / data-pixel-color
function renderPixelIcons() {
  document.querySelectorAll('[data-pixel-icon]').forEach(el => {
    const name = el.getAttribute('data-pixel-icon');
    const size = parseInt(el.getAttribute('data-pixel-size') || '16');
    const color = el.getAttribute('data-pixel-color') || '#0A0A0A';
    el.innerHTML = pixelIconSVG(name, size, color);
  });
  document.querySelectorAll('[data-pixel-logo]').forEach(el => {
    const size = parseInt(el.getAttribute('data-pixel-size') || '28');
    el.innerHTML = pixforgeLogoSVG(size);
  });
}

document.addEventListener('DOMContentLoaded', renderPixelIcons);
